import{_ as o,o as a,c as t,a as n}from"./chunks/framework.8tiMeCK-.js";const h=JSON.parse('{"title":"第 2 章  黑暗森林的火把","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_debugging/ch02_1.md","filePath":"notes/linux_kernel_debugging/ch02_1.md","lastUpdated":null}'),r={name:"notes/linux_kernel_debugging/ch02_1.md"};function c(i,e,l,d,s,p){return a(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="第-2-章-黑暗森林的火把" tabindex="-1">第 2 章 黑暗森林的火把 <a class="header-anchor" href="#第-2-章-黑暗森林的火把" aria-label="Permalink to &quot;第 2 章  黑暗森林的火把&quot;">​</a></h1><p>本章建立的核心认知是：调试内核和调试用户态程序完全是两种物种。在用户态你拥有整个 libc 库、隔离的进程空间和随时可以 attach 的 GDB；到了内核态，你的一个指针错误就能让整个机器瘫痪，而且一旦停机，所有的上下文——除了那一堆十六进制数——都会随断电而烟消云散。</p><p>理解了这一点之后，内核调试工具链那种「笨重」「复杂」甚至「原始」的设计就不再令人费解了——它本质上是带着镣铐跳舞，必须在极度受限的环境中榨取信息。</p><h3 id="环境准备" tabindex="-1">环境准备 <a class="header-anchor" href="#环境准备" aria-label="Permalink to &quot;环境准备&quot;">​</a></h3><p>别急着写代码，先检查装备。</p><p>这听起来像是废话，但请相信我，<strong>环境没配好就往内核代码里冲，是效率最低的折腾方式</strong>。如果你在第一章已经按照「Setting up the workspace」一节搭好了环境，那现在你可以直接复用那一套；如果没有，现在是个好机会回头去补上——我们需要一个稳定的 Linux 开发环境（推荐主机或虚拟机）、交叉编译器链、以及一份能跑通的内核源码。</p><p>这里不重复那些琐碎的 <code>apt install</code> 列表了，但你必须确保手头有以下两样东西随时待命：</p><ol><li><strong>构建工具链</strong>：能编译内核和模块的 <code>gcc</code>/<code>make</code> 工具集。</li><li><strong>目标系统</strong>：一个可以被折腾的 Linux 系统（可以是 QEMU 虚拟机，也可以是一块板子），你能够通过串口或网络看到它的输出，甚至能让它在崩溃时停下来等你检查。</li></ol><p><strong>别跳过这一步</strong>。等到后面你看着满屏毫无意义的寄存器发呆时，会感激现在多花的那十分钟。</p><hr><h2 id="_2-1-技术需求与技术栈" tabindex="-1">2.1 技术需求与技术栈 <a class="header-anchor" href="#_2-1-技术需求与技术栈" aria-label="Permalink to &quot;2.1  技术需求与技术栈&quot;">​</a></h2><h3 id="硬件与软件前提" tabindex="-1">硬件与软件前提 <a class="header-anchor" href="#硬件与软件前提" aria-label="Permalink to &quot;硬件与软件前提&quot;">​</a></h3><p>和上一章一样，我们要在这里统一一下「频道」。</p><p>不管是本地的虚拟机还是远程的开发板，接下来的所有演示都假设你拥有以下控制权：</p><ul><li>** root 权限**：内核调试不跟你讲礼貌，加载模块、查看内核内存 (<code>/dev/mem</code>)、配置调试接口，这些都需要 root。</li><li><strong>内核源码树</strong>：你手里得有一份和目标机器运行版本<strong>完全一致</strong>的源码（或者至少版本号对得上）。用不匹配的源码去分析崩溃堆栈，就像拿着英文地图去找中文路牌——大概能对上，但关键时刻一定迷路。</li></ul><h3 id="工作空间检查清单" tabindex="-1">工作空间检查清单 <a class="header-anchor" href="#工作空间检查清单" aria-label="Permalink to &quot;工作空间检查清单&quot;">​</a></h3><p>让我们快速过一遍工作空间的清单。</p><p>不需要你重新打字，但请在脑子里点个卯：</p><ul><li><strong>编译器</strong>：<code>arm-linux-gnueabihf-gcc</code> 或 <code>x86_64-linux-gnu-gcc</code> 在你的 <code>$PATH</code> 里吗？</li><li><strong>内核配置</strong>：<code>.config</code> 文件里是不是打开了 <code>CONFIG_DEBUG_KERNEL</code> 和 <code>CONFIG_KGDB</code>？（如果这些词看着眼生，别慌，我们马上会细讲）。</li><li><strong>串口/网络</strong>：你能用 <code>minicom</code>、<code>picocom</code> 或者 <code>ssh</code> 连上目标机器吗？</li></ul><p><strong>这里千万别偷懒</strong>。</p><p>如果你在上一章搭建环境时跳过了某些步骤，觉得「暂时用不上」，现在就是「算账」的时候。很多调试工具——特别是后面要讲到的 KGDB 和 kdump——对内核版本和配置极度敏感。差一个补丁版本，或者少了一个 <code>.config</code> 选项，你可能会遇到完全没有任何输出，或者更糟：输出一堆误导性的乱码。</p><p>先别急着敲代码。</p><p>如果这些都 OK，那我们就正式进入内核调试的丛林——先要知道我们要打的是什么样的野兽。</p><hr>',24)])])}const _=o(r,[["render",c]]);export{h as __pageData,_ as default};
